const orders = [
  { id: 1, status: 'pending' },
  { id: 2, status: 'shipped' },
  { id: 3, status: 'pending' },
  { id: 4, status: 'delivered' },
  { id: 5, status: 'shipped' },
];

const grouped = orders.reduce((groups, order) => {
  const key = order.status;
  if (!groups[key]) groups[key] = [];
  groups[key].push(order);
  return groups;
}, {});

console.log(grouped);
// {
//   pending:   [{ id: 1 }, { id: 3 }],
//   shipped:   [{ id: 2 }, { id: 5 }],
