const nested = [[1, 2], [3, 4], [5, 6]];

const flat = nested.reduce((acc, arr) => acc.concat(arr), []);
console.log(flat); // [1, 2, 3, 4, 5, 6]

// Note: for simple flattening, Array.flat() is cleaner:
const flat2 = nested.flat();
console.log(flat2); // [1, 2, 3, 4, 5, 6]

function CartSummary({ items }) {
  const subtotal = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const itemCount = items.reduce((n, item) => n + item.quantity, 0);

  return (
    <div className="cart-summary">
      <p>{itemCount} items</p>
      <p>Subtotal: ${subtotal.toFixed(2)}</p>
    </div>
  );
}

import { useState, useEffect } from 'react';

function App() {
  const [postsById, setPostsById] = useState({});

  useEffect(() => {
    fetch('/api/posts')
      .then(r => r.json())
      .then(posts => {
        // Normalize array to lookup object
        const map = posts.reduce((acc, post) => {
          acc[post.id] = post;
          return acc;
        }, {});
        setPostsById(map);
      });
  }, []);

  // Any component can now do postsById[id] in O(1)
}

// useReducer is reduce() over time:
// (state, action) => newState

function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM':
      return [...state, action.item];
    case 'REMOVE_ITEM':
      return state.filter(item => item.id !== action.id);
    default:
      return state;
  }
}

// ❌ No initial value — uses first element as initial accumulator
// Works for simple sums, but breaks on empty arrays
const total = [].reduce((sum, n) => sum + n);
// TypeError: Reduce of empty array with no initial value

// ✅ Always provide an initial value
const total2 = [].reduce((sum, n) => sum + n, 0); // 0

// ❌ Mutates the accumulator object — works by accident but violates immutability
const index = users.reduce((map, user) => {
  map[user.id] = user;  // mutating map is okay here since we created it as {}
  return map;           // but in React reducers, never mutate state objects
}, {});

// ✅ For object accumulators created fresh in initialValue, mutation is safe
// But in useReducer / Redux, always return a new object:
const newState = { ...state, [action.id]: action.data };

// ❌ Callback doesn't return the accumulator — becomes undefined on next iteration
const total = [1, 2, 3].reduce((sum, n) => {
  sum + n;  // result not returned
}, 0);
console.log(total); // undefined

// ✅ Always return the new accumulator value
const total2 = [1, 2, 3].reduce((sum, n) => {
  return sum + n;
}, 0);
console.log(total2); // 6

// ❌ Using reduce() to double values — overly complex
const doubled = [1, 2, 3].reduce((acc, n) => [...acc, n * 2], []);

// ✅ Just use map()
const doubled2 = [1, 2, 3].map(n => n * 2);
